'use client';

import React, { useState, useEffect } from 'react';
import { cn } from '@/lib/utils';
import { Activity, Wrench, CheckCircle, AlertTriangle, XCircle, Plus, Edit2, Save, X, Trash2 } from 'lucide-react';
import { useGymStore } from '@/lib/store';

interface System {
  id: string;
  name: string;
  status: string;
  reportedAt?: string;
  [key: string]: unknown;
}

export default function MaintenancePage() {
    // Determine hydration
    const [isMounted, setIsMounted] = useState(false);
     
    // eslint-disable-next-line
    useEffect(() => setIsMounted(true), []);

    const { systems, setSystems, updateSystem } = useGymStore();
    const [editingId, setEditingId] = useState<string | null>(null);
    const [editName, setEditName] = useState('');

    if (!isMounted) return null;

    // Handlers
    const updateStatus = (id: string, status: string) => {
        const sys = systems.find(s => s.id === id);
        if (sys) updateSystem({ ...sys, status });
    };

    const attemptReport = () => {
        const newSystem = {
            id: `s${Date.now()}`,
            name: 'New Issue (Click to Edit)',
            status: 'Operational',
            reportedAt: new Date().toISOString()
        };
        setSystems([newSystem, ...systems]);
        // Auto-start edit for convenience
        setEditingId(newSystem.id);
        setEditName(newSystem.name);
    };

    const startEdit = (sys: System) => {
        setEditingId(sys.id);
        setEditName(sys.name);
    };

    const saveEdit = () => {
        if (!editingId) return;
        const sys = systems.find(s => s.id === editingId);
        if (sys) {
            updateSystem({ ...sys, name: editName });
        }
        setEditingId(null);
        setEditName('');
    };

    const cancelEdit = () => {
        setEditingId(null);
        setEditName('');
    };

    const deleteSystem = (id: string) => {
        if (confirm('Are you sure you want to remove this system log?')) {
            setSystems(systems.filter(s => s.id !== id));
        }
    }

    const formatDate = (isoString: string) => {
        try {
            return new Date(isoString).toLocaleString('en-US', {
                month: 'short', day: 'numeric', hour: 'numeric', minute: 'numeric', hour12: true
            });
        } catch (e) {
            return 'Invalid Date';
        }
    };

    const StatusBadge = ({ status }: { status: string }) => {
        if (status === 'Operational') return <div className="flex items-center gap-1.5 text-xs font-bold text-emerald-500 bg-emerald-500/10 px-2 py-1 rounded border border-emerald-500/20"><CheckCircle size={12} /> OPERATIONAL</div>;
        if (status === 'Maintenance') return <div className="flex items-center gap-1.5 text-xs font-bold text-amber-500 bg-amber-500/10 px-2 py-1 rounded border border-amber-500/20"><Wrench size={12} /> MAINTENANCE</div>;
        return <div className="flex items-center gap-1.5 text-xs font-bold text-red-500 bg-red-500/10 px-2 py-1 rounded border border-red-500/20"><XCircle size={12} /> OFFLINE</div>;
    };

    return (
        <div className="space-y-6 pb-20">
             <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-2xl font-bold text-white tracking-tight">System Health</h1>
                    <p className="text-slate-400 text-sm">Monitor and update facility infrastructure status.</p>
                </div>
                <button 
                    onClick={attemptReport}
                    className="flex items-center gap-2 px-4 py-2 bg-slate-800 hover:bg-slate-700 text-white font-medium rounded-lg transition-colors border border-slate-700"
                >
                    <Plus size={18} />
                    Report New Issue
                </button>
            </div>

            <div className="bg-slate-900/50 border border-slate-800 rounded-xl overflow-hidden">
                <table className="w-full text-left text-sm">
                    <thead className="bg-slate-950/50 text-slate-400 uppercase font-medium text-xs">
                        <tr>
                            <th className="px-6 py-4">System Name</th>
                            <th className="px-6 py-4">Current Status</th>
                            <th className="px-6 py-4">Reported At</th>
                            <th className="px-6 py-4 text-right">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-800/50">
                        {systems.map((sys) => {
                            const isEditing = editingId === sys.id;
                            return (
                                <tr key={sys.id} className="hover:bg-slate-800/30 transition-colors group">
                                    <td className="px-6 py-4 font-medium text-white">
                                        <div className="flex items-center gap-3">
                                            <div className={cn("w-2 h-2 rounded-full flex-shrink-0", 
                                                sys.status === 'Operational' ? "bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.5)]" : 
                                                sys.status === 'Maintenance' ? "bg-amber-500 shadow-[0_0_8px_rgba(245,158,11,0.5)]" : 
                                                "bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.5)]"
                                            )} />
                                            
                                            {isEditing ? (
                                                <div className="flex items-center gap-2">
                                                    <input 
                                                        value={editName}
                                                        onChange={(e) => setEditName(e.target.value)}
                                                        className="bg-slate-950 border border-slate-700 rounded px-2 py-1 text-white text-sm focus:border-[#00FFCC] outline-none"
                                                        autoFocus
                                                    />
                                                    <button onClick={saveEdit} className="text-[#00FFCC] hover:bg-[#00FFCC]/10 p-1 rounded"><Save size={14} /></button>
                                                    <button onClick={cancelEdit} className="text-red-500 hover:bg-red-500/10 p-1 rounded"><X size={14} /></button>
                                                </div>
                                            ) : (
                                                <div className="flex items-center gap-2">
                                                    <span>{sys.name}</span>
                                                    <button 
                                                        onClick={() => startEdit(sys)} 
                                                        className="opacity-0 group-hover:opacity-100 transition-opacity text-slate-500 hover:text-[#00FFCC] p-1"
                                                    >
                                                        <Edit2 size={12} />
                                                    </button>
                                                </div>
                                            )}
                                        </div>
                                    </td>
                                    <td className="px-6 py-4">
                                        <StatusBadge status={sys.status} />
                                    </td>
                                    <td className="px-6 py-4 text-slate-500 font-mono text-xs">
                                        {sys.reportedAt ? formatDate(sys.reportedAt) : 'N/A'}
                                    </td>
                                    <td className="px-6 py-4 text-right">
                                        <div className="flex items-center justify-end gap-1 bg-slate-950 p-1 rounded-lg border border-slate-800 inline-flex">
                                            <button 
                                                onClick={() => updateStatus(sys.id, 'Operational')}
                                                className={cn("p-1.5 rounded transition-colors", sys.status === 'Operational' ? "bg-emerald-500 text-slate-950 shadow" : "text-slate-500 hover:text-emerald-500")}
                                                title="Set Operational"
                                            >
                                                <CheckCircle size={14} />
                                            </button>
                                            <button 
                                                onClick={() => updateStatus(sys.id, 'Maintenance')}
                                                className={cn("p-1.5 rounded transition-colors", sys.status === 'Maintenance' ? "bg-amber-500 text-slate-950 shadow" : "text-slate-500 hover:text-amber-500")}
                                                title="Set Maintenance"
                                            >
                                                <Wrench size={14} />
                                            </button>
                                            <button 
                                                onClick={() => updateStatus(sys.id, 'Not Working')}
                                                className={cn("p-1.5 rounded transition-colors", sys.status === 'Not Working' ? "bg-red-500 text-white shadow" : "text-slate-500 hover:text-red-500")}
                                                title="Set Not Working"
                                            >
                                                <AlertTriangle size={14} />
                                            </button>
                                            <div className="w-[1px] h-4 bg-slate-800 mx-1" />
                                            <button 
                                                onClick={() => deleteSystem(sys.id)}
                                                className="p-1.5 rounded text-slate-500 hover:text-red-500 hover:bg-red-500/10 transition-colors"
                                                title="Delete Log"
                                            >
                                                <Trash2 size={14} />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
            </div>
        </div>
    );
}

'use client';

import React, { useState } from 'react';
import { cn } from '@/lib/utils';
import { 
  User, QrCode, MessageSquare, Printer, Pause, Fingerprint, Activity, 
  CreditCard, Calendar, Clock, AlertTriangle, Edit2, Save, X, Check,
  ChevronDown, ChevronUp, Trash2, Plus
} from 'lucide-react';

// Types
type Note = {
    id: string;
    content: string;
    date: string;
    author: string;
}

// Mock Data for a specific member
const memberProfile = {
  id: 'M-2024-001',
  name: 'Sarah Chen',
  role: 'Member',
  status: 'Active',
  tier: 'Annual Pro',
  joinDate: '2023-01-15',
  avatar: null, // Placeholder logic
  biometrics: {
    registered: true,
    lastAccess: [
      { id: 1, location: 'Main Gate', time: '10:42 AM Today', method: 'Biometric' }, // 1
      { id: 2, location: 'Main Gate', time: '06:15 PM Yesterday', method: 'Biometric' }, // 2
      { id: 3, location: 'Main Gate', time: '07:30 AM 2 days ago', method: 'App QR' }, // 3
      { id: 4, location: 'Yoga Studio', time: '08:00 AM 2 days ago', method: 'Keypad' }, // 4
      { id: 5, location: 'Main Gate', time: '05:45 PM 3 days ago', method: 'Biometric' }, // 5
    ]
  },
  financials: {
    plan: 'Annual Pro',
    nextBilling: '2025-01-15',
    balance: '₹0.00',
    pendingFees:  '₹0.00', 
    history: [
      { id: 1, date: '2024-01-15', amount: '₹15,000', status: 'Success', method: 'Credit Card' },
      { id: 2, date: '2023-01-15', amount: '₹12,000', status: 'Success', method: 'UPI' },
    ]
  },
  wellness: {
    visitsThisWeek: 4,
    totalVisits: 142,
    streak: 12,
    anniversary: 'Jan 15',
    heatmap: Array.from({ length: 52 * 7 }).map(() => Math.random() > 0.7)
  },
  initialNotes: [
      { id: 'n1', content: 'Member recovering from minor shoulder injury. Suggested avoiding heavy overhead presses for 2 weeks.', date: '2024-01-20 10:30 AM', author: 'Mike (Trainer)' },
      { id: 'n2', content: 'Interested in Yoga classes. Added to the interest list for next batch.', date: '2024-01-15 09:12 AM', author: 'Admin' }
  ] as Note[]
};

export default function MemberProfilePage({ params }: { params: { id: string } }) {
  // Access Log State
  const [showAllLogs, setShowAllLogs] = useState(false);
  const displayedLogs = showAllLogs ? memberProfile.biometrics.lastAccess : memberProfile.biometrics.lastAccess.slice(0, 3);

  // Notes State
  const [notes, setNotes] = useState<Note[]>(memberProfile.initialNotes);
  const [isAddingNote, setIsAddingNote] = useState(false);
  const [newNoteContent, setNewNoteContent] = useState('');
  const [editingNoteId, setEditingNoteId] = useState<string | null>(null);
  const [editContent, setEditContent] = useState('');

  // Note Handlers
  const addNote = () => {
      if (!newNoteContent.trim()) return;
      const newNote: Note = {
          id: Date.now().toString(),
          content: newNoteContent,
          date: new Date().toLocaleString(), // Simple local formatting
          author: 'CurrentUser' // placeholder
      };
      setNotes([newNote, ...notes]);
      setNewNoteContent('');
      setIsAddingNote(false);
  };

  const deleteNote = (id: string) => {
      setNotes(notes.filter(n => n.id !== id));
  };

  const startEdit = (note: Note) => {
      setEditingNoteId(note.id);
      setEditContent(note.content);
  };

  const saveEdit = (id: string) => {
      setNotes(notes.map(n => n.id === id ? { ...n, content: editContent, date: `${n.date} (Edited)` } : n));
      setEditingNoteId(null);
  };

  return (
    <div className="space-y-6 pb-20">
      {/* Header & Identity */}
      <div className="bg-slate-900/50 border border-slate-800 rounded-2xl p-6 flex flex-col md:flex-row items-start md:items-center justify-between gap-6 relative overflow-hidden group">
         <div className="absolute top-0 right-0 p-8 opacity-5 font-black text-9xl text-slate-700 pointer-events-none select-none">
             {memberProfile.id.split('-')[1]}
         </div>

         <div className="flex items-center gap-6 relative z-10">
             <div className="w-24 h-24 rounded-full bg-slate-800 border-4 border-slate-900 flex items-center justify-center text-3xl font-bold text-slate-400 shadow-2xl">
                 {memberProfile.avatar || memberProfile.name.charAt(0)}
             </div>
             <div>
                 <div className="flex items-center gap-3 mb-1">
                     <h1 className="text-3xl font-bold text-white tracking-tight">{memberProfile.name}</h1>
                     <span className={cn("px-2 py-0.5 rounded text-xs font-bold border uppercase tracking-wider", 
                         memberProfile.status === 'Active' ? "bg-emerald-500/10 text-emerald-500 border-emerald-500/20" : 
                         "bg-red-500/10 text-red-500 border-red-500/20")}>
                         {memberProfile.status}
                     </span>
                 </div>
                 <div className="flex items-center gap-4 text-sm text-slate-400">
                     <span className="font-mono">{memberProfile.id}</span>
                     <span className="w-1 h-1 bg-slate-600 rounded-full" />
                     <span>Joined {memberProfile.joinDate}</span>
                     <span className="w-1 h-1 bg-slate-600 rounded-full" />
                     <span className="text-[#00FFCC] font-bold">{memberProfile.tier}</span>
                 </div>
             </div>
         </div>

         <div className="flex items-center gap-3 relative z-10 w-full md:w-auto">
             <button className="flex-1 md:flex-none py-2 px-4 bg-slate-800 hover:bg-slate-700 text-white rounded-lg flex items-center justify-center gap-2 text-sm font-medium transition-colors border border-slate-700">
                 <Pause size={16} /> Pause
             </button>
             <button className="flex-1 md:flex-none py-2 px-4 bg-slate-800 hover:bg-slate-700 text-white rounded-lg flex items-center justify-center gap-2 text-sm font-medium transition-colors border border-slate-700">
                 <Printer size={16} /> Pass
             </button>
             <button className="flex-1 md:flex-none py-2 px-4 bg-[#00FFCC] hover:bg-[#00FFCC]/90 text-slate-950 rounded-lg flex items-center justify-center gap-2 text-sm font-bold shadow-[0_0_15px_rgba(0,255,204,0.3)] transition-all">
                 <MessageSquare size={16} /> Message
             </button>
         </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Left Column: Financials & Biometrics (Swapped) */}
          <div className="space-y-6">
              
              {/* Financial Card (Shifted Up) */}
              <div className="bg-slate-900/50 border border-slate-800 rounded-xl p-5">
                  <h3 className="text-slate-400 text-xs font-bold uppercase tracking-wider mb-4 flex items-center gap-2">
                      <CreditCard size={16} className="text-amber-500" /> Financials
                  </h3>

                  <div className="grid grid-cols-2 gap-3 mb-6">
                      <div className="p-3 bg-slate-950/50 rounded-lg border border-slate-800">
                          <div className="text-xs text-slate-500 mb-1">Current Plan</div>
                          <div className="text-sm font-bold text-white">{memberProfile.financials.plan}</div>
                      </div>
                      <div className="p-3 bg-slate-950/50 rounded-lg border border-slate-800">
                          <div className="text-xs text-slate-500 mb-1">Next Billing</div>
                          <div className="text-sm font-bold text-white">{memberProfile.financials.nextBilling}</div>
                      </div>
                  </div>

                  {(memberProfile.financials.pendingFees !== '₹0.00') && (
                      <div className="mb-6 p-3 bg-amber-500/10 border border-amber-500/20 rounded-lg flex items-center gap-3">
                          <AlertTriangle className="text-amber-500" size={20} />
                          <div>
                              <div className="text-sm font-bold text-amber-500">Pending Fees: {memberProfile.financials.pendingFees}</div>
                              <div className="text-xs text-amber-500/80">Immediate payment required</div>
                          </div>
                      </div>
                  )}

                  <div className="space-y-2">
                      <h4 className="text-xs font-medium text-slate-500 mb-3">Payment History</h4>
                      <table className="w-full text-xs text-left">
                          <thead className="text-slate-500 border-b border-slate-800">
                              <tr>
                                  <th className="pb-2">Date</th>
                                  <th className="pb-2">Amount</th>
                                  <th className="pb-2 text-right">Status</th>
                              </tr>
                          </thead>
                          <tbody className="divide-y divide-slate-800/50">
                              {memberProfile.financials.history.map((tx) => (
                                  <tr key={tx.id}>
                                      <td className="py-2 text-slate-300">{tx.date}</td>
                                      <td className="py-2 text-white font-medium">{tx.amount}</td>
                                      <td className="py-2 text-right">
                                          <span className="text-emerald-500">{tx.status}</span>
                                      </td>
                                  </tr>
                              ))}
                          </tbody>
                      </table>
                  </div>
              </div>

              {/* Biometrics Module (Shifted Down) */}
              <div className="bg-slate-900/50 border border-slate-800 rounded-xl p-5">
                  <h3 className="text-slate-400 text-xs font-bold uppercase tracking-wider mb-4 flex items-center gap-2">
                      <Fingerprint size={16} className="text-[#00FFCC]" /> Access Control
                  </h3>
                  
                  <div className="flex items-center justify-between p-4 bg-slate-950/50 rounded-lg border border-slate-800 mb-6">
                      <div className="flex items-center gap-3">
                          <div className={cn("p-2 rounded-lg", memberProfile.biometrics.registered ? "bg-emerald-500/10 text-emerald-500" : "bg-red-500/10 text-red-500")}>
                              {memberProfile.biometrics.registered ? <Check size={20} /> : <X size={20} />}
                          </div>
                          <div>
                              <div className="text-sm font-bold text-white">Biometric Status</div>
                              <div className="text-xs text-slate-500">{memberProfile.biometrics.registered ? "Registered & Active" : "Not Registered"}</div>
                          </div>
                      </div>
                      <button className="text-xs text-slate-400 hover:text-white underline">Manage</button>
                  </div>

                  <div className="space-y-3">
                      <div className="flex items-center justify-between">
                          <h4 className="text-xs font-medium text-slate-500">Recent Access Log</h4>
                      </div>
                      
                      <div className="space-y-0 relative">
                          <div className="absolute left-1.5 top-2 bottom-2 w-px bg-slate-800" />
                          {displayedLogs.map((log) => (
                              <div key={log.id} className="relative pl-6 py-2 flex items-center justify-between group">
                                  <div className="absolute left-0 top-1/2 -translate-y-1/2 w-3 h-3 rounded-full bg-slate-900 border border-slate-700 group-hover:border-[#00FFCC] transition-colors z-10" />
                                  <div>
                                      <div className="text-sm font-medium text-white">{log.location}</div>
                                      <div className="text-xs text-slate-500">{log.time}</div>
                                  </div>
                                  <div className="text-xs text-slate-600 px-2 py-1 bg-slate-800/50 rounded border border-slate-800">
                                      {log.method}
                                  </div>
                              </div>
                          ))}
                      </div>

                      {memberProfile.biometrics.lastAccess.length > 3 && (
                          <button 
                            onClick={() => setShowAllLogs(!showAllLogs)}
                            className="w-full text-center text-xs text-slate-500 hover:text-[#00FFCC] transition-colors py-2 flex items-center justify-center gap-1"
                          >
                             {showAllLogs ? (
                                 <>Show Less <ChevronUp size={12} /></>
                             ) : (
                                 <>Show All Activity <ChevronDown size={12} /></>
                             )}
                          </button>
                      )}
                  </div>
              </div>
          </div>

          {/* Right Column: Wellness & Notes */}
          <div className="lg:col-span-2 space-y-6">
               <div className="bg-slate-900/50 border border-slate-800 rounded-xl p-6">
                   <div className="flex items-center justify-between mb-6">
                       <h3 className="text-slate-400 text-xs font-bold uppercase tracking-wider flex items-center gap-2">
                           <Activity size={16} className="text-[#00FFCC]" /> Growth & Wellness
                       </h3>
                       <div className="flex items-center gap-2 text-xs font-medium">
                           <span className="flex items-center gap-1.5 px-2 py-1 bg-slate-800 rounded text-slate-300">
                               <Clock size={12} className="text-emerald-500" /> Since {memberProfile.joinDate}
                           </span>
                       </div>
                   </div>

                   {/* KPI Cards */}
                   <div className="grid grid-cols-3 gap-4 mb-8">
                       <div className="p-4 bg-slate-950/50 rounded-xl border border-slate-800 text-center">
                           <div className="text-2xl font-black text-white">{memberProfile.wellness.visitsThisWeek}</div>
                           <div className="text-xs text-slate-500 uppercase font-bold tracking-wider">Avg. Visits/Wk</div>
                       </div>
                       <div className="p-4 bg-slate-950/50 rounded-xl border border-slate-800 text-center">
                           <div className="text-2xl font-black text-white">{memberProfile.wellness.totalVisits}</div>
                           <div className="text-xs text-slate-500 uppercase font-bold tracking-wider">Total Active Days</div>
                       </div>
                       <div className="p-4 bg-slate-950/50 rounded-xl border border-slate-800 text-center">
                           <div className="text-2xl font-black text-white">{memberProfile.wellness.anniversary}</div>
                           <div className="text-xs text-slate-500 uppercase font-bold tracking-wider">Anniversary</div>
                       </div>
                   </div>

                   {/* Heatmap */}
                   <div className="mb-8">
                       <h4 className="text-xs font-medium text-slate-500 mb-3">Attendance Heatmap (Last 12 Months)</h4>
                       <div className="flex gap-1 overflow-x-auto pb-2">
                           {Array.from({ length: 52 }).map((_, weekIndex) => (
                               <div key={weekIndex} className="grid grid-rows-7 gap-1">
                                   {Array.from({ length: 7 }).map((_, dayIndex) => {
                                       // Simulated data access
                                       const isActive = memberProfile.wellness.heatmap[weekIndex * 7 + dayIndex];
                                       return (
                                           <div 
                                               key={dayIndex} 
                                               className={cn(
                                                   "w-2.5 h-2.5 rounded-sm transition-all hover:scale-125",
                                                   isActive ? "bg-[#00FFCC] shadow-[0_0_4px_rgba(0,255,204,0.4)]" : "bg-slate-800/50"
                                               )}
                                               title={`Activity on Week ${weekIndex + 1}, Day ${dayIndex + 1}`}
                                            />
                                       );
                                   })}
                               </div>
                           ))}
                       </div>
                   </div>

                   {/* Multi-Notes System */}
                   <div className="relative">
                       <div className="flex items-center justify-between mb-4">
                           <h4 className="text-xs font-medium text-slate-500">Trainer / Admin Notes</h4>
                           <button 
                                onClick={() => setIsAddingNote(true)}
                                className={cn("text-xs flex items-center gap-1 transition-colors px-2 py-1 bg-[#00FFCC]/10 text-[#00FFCC] rounded hover:bg-[#00FFCC]/20")}
                           >
                               <Plus size={12} /> Add Note
                           </button>
                       </div>
                       
                       {/* Add Note Input */}
                       {isAddingNote && (
                           <div className="mb-4 bg-slate-950 border border-slate-800 rounded-xl p-4 animate-in slide-in-from-top-2">
                               <textarea 
                                   value={newNoteContent}
                                   onChange={(e) => setNewNoteContent(e.target.value)}
                                   className="w-full bg-transparent text-sm text-white placeholder-slate-600 outline-none resize-none h-20 mb-2"
                                   placeholder="Type note details here..."
                                   autoFocus
                               />
                               <div className="flex items-center justify-end gap-2">
                                   <button 
                                       onClick={() => setIsAddingNote(false)}
                                       className="text-xs text-slate-400 hover:text-white px-3 py-1.5 rounded"
                                   >
                                       Cancel
                                   </button>
                                   <button 
                                       onClick={addNote}
                                       className="text-xs bg-[#00FFCC] text-slate-950 font-bold px-3 py-1.5 rounded hover:bg-[#00FFCC]/90"
                                   >
                                       Save Note
                                   </button>
                               </div>
                           </div>
                       )}

                       {/* Notes List */}
                       <div className="space-y-3">
                           {notes.map(note => (
                               <div key={note.id} className="group bg-slate-950/30 border border-slate-800 rounded-xl p-4 hover:border-slate-700 transition-colors relative">
                                    {/* Action Buttons */}
                                    <div className="absolute top-4 right-4 flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                        <button 
                                            onClick={() => startEdit(note)}
                                            className="text-slate-500 hover:text-white" 
                                            title="Edit"
                                        >
                                            <Edit2 size={12} />
                                        </button>
                                        <button 
                                            onClick={() => deleteNote(note.id)}
                                            className="text-slate-500 hover:text-red-400" 
                                            title="Delete"
                                        >
                                            <Trash2 size={12} />
                                        </button>
                                    </div>

                                    {editingNoteId === note.id ? (
                                        // Edit Mode
                                        <div>
                                            <textarea 
                                                value={editContent}
                                                onChange={(e) => setEditContent(e.target.value)}
                                                className="w-full bg-slate-900 text-sm text-white p-2 rounded outline-none border border-[#00FFCC]/50 resize-none h-20 mb-2"
                                            />
                                            <div className="flex gap-2 justify-end">
                                                <button onClick={() => setEditingNoteId(null)} className="text-xs text-slate-400">Cancel</button>
                                                <button onClick={() => saveEdit(note.id)} className="text-xs text-[#00FFCC] font-bold">Save</button>
                                            </div>
                                        </div>
                                    ) : (
                                        // View Mode
                                        <>
                                            <p className="text-sm text-slate-300 leading-relaxed mb-3 pr-8 whitespace-pre-wrap">{note.content}</p>
                                            <div className="flex items-center gap-2 text-[10px] text-slate-500 font-mono">
                                                <span>{note.date}</span>
                                                <span className="w-1 h-1 bg-slate-700 rounded-full" />
                                                <span className="text-slate-400">{note.author}</span>
                                            </div>
                                        </>
                                    )}
                               </div>
                           ))}

                           {notes.length === 0 && (
                               <div className="text-center py-8 text-slate-500 text-sm italic">
                                   No notes added yet.
                               </div>
                           )}
                       </div>
                   </div>
               </div>
          </div>
      </div>
    </div>
  );
}

'use client';

import React, { useState, useMemo, useEffect } from 'react';
import { cn } from '@/lib/utils';
import { useGymStore } from '@/lib/store';
import { Search, Filter, MoreHorizontal, X, Check, User, CreditCard, Mail, ArrowUpDown, ChevronUp, ChevronDown } from 'lucide-react';

interface Member {
    id: string;
    name: string;
    tier: string;
    status: string;
    joinDate: string;
    [key: string]: unknown;
}

const SortIcon = ({ columnKey, sortConfig }: { columnKey: string, sortConfig: { key: string, direction: 'asc' | 'desc' } | null }) => {
    if (sortConfig?.key !== columnKey) return <ArrowUpDown size={14} className="opacity-30" />;
    return sortConfig.direction === 'asc' ? <ChevronUp size={14} className="text-emerald-500" /> : <ChevronDown size={14} className="text-emerald-500" />;
};

export default function MembersPage() {
    // Global State
    const { members, setMembers } = useGymStore();
    const safeMembers = (members as Member[]) || [];

    // Search & Filter State
    const [searchTerm, setSearchTerm] = useState('');
    const [isFilterOpen, setIsFilterOpen] = useState(false);
    const [filters, setFilters] = useState({
        tiers: [] as string[],
        statuses: [] as string[]
    });

    // Sorting State
    const [sortConfig, setSortConfig] = useState<{ key: string, direction: 'asc' | 'desc' } | null>(null);

    // Action State
    const [activeActionId, setActiveActionId] = useState<string | null>(null);
    const [modalOpen, setModalOpen] = useState<'profile' | 'plan' | null>(null);
    const [selectedMember, setSelectedMember] = useState<Member | null>(null);

    // Derived Data (Search + Filter + Sort)
    const filteredMembers = useMemo(() => {
        const result = safeMembers.filter((member: Member) => {
            const matchesSearch = member.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                member.id.toLowerCase().includes(searchTerm.toLowerCase());

            const matchesTier = filters.tiers.length === 0 || filters.tiers.includes(member.tier);
            const matchesStatus = filters.statuses.length === 0 || filters.statuses.includes(member.status);

            return matchesSearch && matchesTier && matchesStatus;
        });

        if (sortConfig) {
            result.sort((a: Member, b: Member) => {
                const aVal = a[sortConfig.key] as string | number;
                const bVal = b[sortConfig.key] as string | number;
                if (aVal < bVal) {
                    return sortConfig.direction === 'asc' ? -1 : 1;
                }
                if (aVal > bVal) {
                    return sortConfig.direction === 'asc' ? 1 : -1;
                }
                return 0;
            });
        }

        return result;
    }, [safeMembers, searchTerm, filters, sortConfig]);

    // Handlers
    const handleSort = (key: string) => {
        let direction: 'asc' | 'desc' = 'asc';
        if (sortConfig && sortConfig.key === key && sortConfig.direction === 'asc') {
            direction = 'desc';
        }
        setSortConfig({ key, direction });
    };

    const toggleFilter = (type: 'tiers' | 'statuses', value: string) => {
        setFilters(prev => {
            const current = prev[type];
            return {
                ...prev,
                [type]: current.includes(value) ? current.filter(item => item !== value) : [...current, value]
            };
        });
    };

    const openAction = (id: string, e: React.MouseEvent) => {
        e.stopPropagation(); // Prevent row click or global click
        // If clicking the same one, keep it open (per user request). 
        // Only close if clicking a DIFFERENT one, which setID handles.
        setActiveActionId(id);
    };

    // Close menu when clicking outside (handled by parent div)
    const handleGlobalClick = () => {
        setActiveActionId(null);
    };

    const handleActionClick = (member: Member, type: 'profile' | 'plan') => {
        setSelectedMember(member);
        setModalOpen(type);
        setActiveActionId(null);
    };

    const saveProfile = (e: React.FormEvent) => {
        e.preventDefault();
        const form = e.target as HTMLFormElement;
        const name = (form.elements.namedItem('name') as HTMLInputElement).value;

        const updated = safeMembers.map((m: Member) => selectedMember && m.id === selectedMember.id ? { ...m, name } : m);
        setMembers(updated); // Sync to global
        setModalOpen(null);
    };

    const savePlan = (tier: 'Basic' | 'Business' | 'Enterprise') => {
        const updated = safeMembers.map((m: Member) => selectedMember && m.id === selectedMember.id ? { ...m, tier } : m);
        setMembers(updated); // Sync to global
        setModalOpen(null);
    };


    return (
        <div className="space-y-6 pb-20" onClick={handleGlobalClick}>
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-2xl font-bold text-white tracking-tight">Member Directory</h1>
                    <p className="text-slate-400 text-sm">Manage member profiles, subscriptions, and status.</p>
                </div>
                <div className="flex items-center gap-3">
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                        <input
                            type="text"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            placeholder="Search members..."
                            className="bg-slate-900 border border-slate-800 text-white text-sm rounded-lg pl-10 pr-4 py-2 focus:ring-2 focus:ring-neon/50 focus:border-neon/50 outline-none w-64"
                        />
                    </div>
                    <div className="relative">
                        <button
                            onClick={(e) => { e.stopPropagation(); setIsFilterOpen(!isFilterOpen); }}
                            className={cn(
                                "p-2 border rounded-lg transition-colors relative",
                                isFilterOpen || filters.tiers.length > 0 || filters.statuses.length > 0
                                    ? "bg-emerald-500/10 border-emerald-500/50 text-emerald-500"
                                    : "bg-slate-800 border-slate-700 text-slate-400 hover:text-white"
                            )}
                        >
                            <Filter size={18} />
                            {(filters.tiers.length > 0 || filters.statuses.length > 0) && (
                                <div className="absolute -top-1 -right-1 w-3 h-3 bg-emerald-500 rounded-full border-2 border-slate-950" />
                            )}
                        </button>

                        {/* Filter Dropdown */}
                        {isFilterOpen && (
                            <div
                                className="absolute right-0 top-full mt-2 w-64 bg-slate-900 border border-slate-800 rounded-xl shadow-2xl z-20 p-4"
                                onClick={(e) => e.stopPropagation()}
                            >
                                <h3 className="text-xs font-bold text-slate-500 uppercase mb-3">Filter by Tier</h3>
                                <div className="space-y-2 mb-4">
                                    {['Basic', 'Business', 'Enterprise'].map(tier => (
                                        <label key={tier} className="flex items-center gap-2 text-sm text-slate-300 cursor-pointer hover:text-white">
                                            <input
                                                type="checkbox"
                                                checked={filters.tiers.includes(tier)}
                                                onChange={() => toggleFilter('tiers', tier)}
                                                className="rounded border-slate-700 bg-slate-800 text-emerald-500 focus:ring-emerald-500/50"
                                            />
                                            {tier}
                                        </label>
                                    ))}
                                </div>

                                <div className="border-t border-slate-800 my-3" />

                                <h3 className="text-xs font-bold text-slate-500 uppercase mb-3">Filter by Status</h3>
                                <div className="space-y-2">
                                    {['Active', 'Frozen', 'Cancelled'].map(status => (
                                        <label key={status} className="flex items-center gap-2 text-sm text-slate-300 cursor-pointer hover:text-white">
                                            <input
                                                type="checkbox"
                                                checked={filters.statuses.includes(status)}
                                                onChange={() => toggleFilter('statuses', status)}
                                                className="rounded border-slate-700 bg-slate-800 text-emerald-500 focus:ring-emerald-500/50"
                                            />
                                            {status}
                                        </label>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </div>

            <div className="bg-slate-900/50 border border-slate-800 rounded-xl overflow-visible">
                <table className="w-full text-left text-sm">
                    <thead className="bg-slate-950/50 text-slate-400 uppercase font-medium text-xs">
                        <tr>
                            <th className="px-6 py-4 cursor-pointer hover:text-white hover:bg-slate-900/50 transition-colors" onClick={(e) => { e.stopPropagation(); handleSort('name'); }}>
                                <div className="flex items-center gap-2">Member Info <SortIcon columnKey="name" sortConfig={sortConfig} /></div>
                            </th>
                            <th className="px-6 py-4 cursor-pointer hover:text-white hover:bg-slate-900/50 transition-colors" onClick={(e) => { e.stopPropagation(); handleSort('tier'); }}>
                                <div className="flex items-center gap-2">Tier <SortIcon columnKey="tier" sortConfig={sortConfig} /></div>
                            </th>
                            <th className="px-6 py-4 cursor-pointer hover:text-white hover:bg-slate-900/50 transition-colors" onClick={(e) => { e.stopPropagation(); handleSort('status'); }}>
                                <div className="flex items-center gap-2">Status <SortIcon columnKey="status" sortConfig={sortConfig} /></div>
                            </th>
                            <th className="px-6 py-4 cursor-pointer hover:text-white hover:bg-slate-900/50 transition-colors" onClick={(e) => { e.stopPropagation(); handleSort('joinDate'); }}>
                                <div className="flex items-center gap-2">Join Date <SortIcon columnKey="joinDate" sortConfig={sortConfig} /></div>
                            </th>
                            <th className="px-6 py-4">
                                Expiry (Est)
                            </th>
                            <th className="px-6 py-4 text-right">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-800/50">
                        {filteredMembers.map((member) => (
                            <tr
                                key={member.id}
                                className={cn(
                                    "transition-all duration-300 group",
                                    activeActionId === member.id ? "bg-emerald-500/5 border-emerald-500/30 shadow-[inset_2px_0_0_0_rgb(16,185,129)]" : "hover:bg-slate-800/30"
                                )}
                            >
                                <td className="px-6 py-4">
                                    <div className="flex items-center gap-3">
                                        <div className="w-8 h-8 rounded-full bg-slate-800 flex items-center justify-center text-xs font-bold text-slate-300">
                                            {member.name.charAt(0)}
                                        </div>
                                        <div>
                                            <div className={cn("font-medium", activeActionId === member.id ? "text-emerald-400" : "text-white")}>{member.name}</div>
                                            <div className="text-xs text-slate-500">ID: {member.id}</div>
                                        </div>
                                    </div>
                                </td>
                                <td className="px-6 py-4">
                                    <span className={cn(
                                        "px-2 py-1 rounded text-xs font-bold border",
                                        member.tier === 'Enterprise' ? "bg-purple-500/10 text-purple-400 border-purple-500/20" :
                                            member.tier === 'Business' ? "bg-blue-500/10 text-blue-400 border-blue-500/20" :
                                                "bg-slate-800 text-slate-400 border-slate-700"
                                    )}>
                                        {member.tier}
                                    </span>
                                </td>
                                <td className="px-6 py-4">
                                    <div className="flex items-center gap-2">
                                        <div className={cn("w-2 h-2 rounded-full",
                                            member.status === 'Active' ? "bg-emerald-500" :
                                                member.status === 'Frozen' ? "bg-amber-500" : "bg-red-500"
                                        )} />
                                        <span className="text-slate-300">{member.status}</span>
                                    </div>
                                </td>
                                <td className="px-6 py-4 text-slate-400 font-mono">
                                    {member.joinDate}
                                </td>
                                <td className="px-6 py-4 text-slate-400 font-mono">
                                    {new Date(new Date(member.joinDate).setFullYear(new Date(member.joinDate).getFullYear() + 1)).toISOString().split('T')[0]}
                                </td>
                                <td className="px-6 py-4 text-right relative">
                                    <button
                                        onClick={(e) => openAction(member.id, e)}
                                        className={cn(
                                            "transition-colors p-1 rounded",
                                            activeActionId === member.id ? "bg-emerald-500 text-slate-950" : "text-slate-500 hover:text-white"
                                        )}
                                    >
                                        <MoreHorizontal size={16} />
                                    </button>

                                    {/* Action Menu */}
                                    {activeActionId === member.id && (
                                        <div
                                            className="absolute right-8 top-8 z-30 w-48 bg-slate-900 border border-slate-800 rounded-xl shadow-xl overflow-hidden animate-in fade-in zoom-in-95 duration-200"
                                            onClick={(e) => e.stopPropagation()} // Clicking menu shouldn't close it
                                        >
                                            <button
                                                onClick={() => handleActionClick(member, 'profile')}
                                                className="w-full text-left px-4 py-3 text-sm text-slate-300 hover:bg-slate-800 hover:text-white flex items-center gap-2"
                                            >
                                                <User size={14} /> Modify Profile
                                            </button>
                                            <button
                                                onClick={() => handleActionClick(member, 'plan')}
                                                className="w-full text-left px-4 py-3 text-sm text-slate-300 hover:bg-slate-800 hover:text-white flex items-center gap-2 border-t border-slate-800"
                                            >
                                                <CreditCard size={14} /> Change Plan
                                            </button>
                                        </div>
                                    )}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>

                {filteredMembers.length === 0 && (
                    <div className="p-12 text-center text-slate-500">
                        No members found matching your filters.
                    </div>
                )}
            </div>

            {/* Modify Profile Modal */}
            {modalOpen === 'profile' && selectedMember && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4" onClick={(e) => e.stopPropagation()}>
                    <div className="bg-slate-900 border border-slate-800 rounded-2xl w-full max-w-md p-6 shadow-2xl relative" onClick={e => e.stopPropagation()}>
                        <button onClick={() => setModalOpen(null)} className="absolute top-4 right-4 text-slate-500 hover:text-white"><X size={20} /></button>
                        <h3 className="text-lg font-bold text-white mb-6">Modify Profile</h3>
                        <form onSubmit={saveProfile} className="space-y-4">
                            <div>
                                <label className="text-xs font-bold text-slate-500 uppercase">Full Name</label>
                                <div className="relative mt-1">
                                    <User className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                                    <input defaultValue={selectedMember.name} name="name" className="w-full bg-slate-950 border border-slate-800 rounded-lg pl-10 pr-4 py-2 text-white focus:ring-2 focus:ring-emerald-500/50 outline-none" />
                                </div>
                            </div>
                            <div>
                                <label className="text-xs font-bold text-slate-500 uppercase">Email (Read Only)</label>
                                <div className="relative mt-1">
                                    <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" size={16} />
                                    <input value={`${selectedMember.id}@example.com`} readOnly className="w-full bg-slate-950/50 border border-slate-800 rounded-lg pl-10 pr-4 py-2 text-slate-500 cursor-not-allowed" />
                                </div>
                            </div>
                            <div className="pt-4 flex gap-3">
                                <button type="button" onClick={() => setModalOpen(null)} className="flex-1 py-2 rounded-lg text-slate-400 hover:bg-slate-800">Cancel</button>
                                <button type="submit" className="flex-1 py-2 bg-emerald-600 hover:bg-emerald-500 text-white rounded-lg font-medium">Save Changes</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {/* Change Plan Modal */}
            {modalOpen === 'plan' && selectedMember && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4" onClick={(e) => e.stopPropagation()}>
                    <div className="bg-slate-900 border border-slate-800 rounded-2xl w-full max-w-md p-6 shadow-2xl relative" onClick={e => e.stopPropagation()}>
                        <button onClick={() => setModalOpen(null)} className="absolute top-4 right-4 text-slate-500 hover:text-white"><X size={20} /></button>
                        <h3 className="text-lg font-bold text-white mb-2">Change Subscription Plan</h3>
                        <p className="text-sm text-slate-400 mb-6">Current Plan: <span className="text-white font-bold">{selectedMember.tier}</span></p>

                        <div className="space-y-3">
                            {['Basic', 'Business', 'Enterprise'].map((tier: string) => (
                                <button
                                    key={tier}
                                    onClick={() => savePlan(tier as "Basic" | "Business" | "Enterprise")}
                                    className={cn(
                                        "w-full p-4 rounded-xl border flex items-center justify-between transition-all",
                                        selectedMember.tier === tier ? "bg-emerald-500/10 border-emerald-500 text-white" : "bg-slate-950 border-slate-800 text-slate-400 hover:border-slate-700"
                                    )}
                                >
                                    <span className="font-medium">{tier} Plan</span>
                                    {selectedMember.tier === tier && <Check size={18} className="text-emerald-500" />}
                                </button>
                            ))}
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

import React, { useState, useEffect } from 'react';
import { cn } from '@/lib/utils';
import { useGymStore } from '@/lib/store';
import { Search, Plus, Shield, ShieldAlert, MoreHorizontal, X, Check } from 'lucide-react';

interface StaffMember {
  id: string;
  name: string;
  role: string;
  email: string;
  access: string;
  status: string;
  [key: string]: unknown;
}

export default function StaffPage() {
  const { staff, setStaff } = useGymStore();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isAdmin, setIsAdmin] = useState(false);
  
  // Sync
  const safeStaff = staff || [];

  // Handle Add Staff
  const handleAddStaff = () => {
     // Create a new staff object and save to store
     // Implementation detail: we need form state
     const newStaff = {
         id: `s${Date.now()}`,
         name: "New Staff", // Placeholder for now as form is static in original
         role: "Trainer",
         email: "staff@example.com",
         access: isAdmin ? 'Admin' : 'Read-Only',
         status: 'Active'
     };
     setStaff([...(staff || []), newStaff]);
     setIsModalOpen(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white tracking-tight">Staff Management</h1>
          <p className="text-slate-400 text-sm">Control staff access and permissions.</p>
        </div>
        <button 
            onClick={() => setIsModalOpen(true)}
            className="flex items-center gap-2 px-4 py-2 bg-emerald-600 hover:bg-emerald-500 text-white font-medium rounded-lg transition-colors shadow-lg shadow-emerald-500/20"
        >
            <Plus size={16} />
            Add Staff
        </button>
      </div>

      {/* Staff List */}
      <div className="bg-slate-900/50 border border-slate-800 rounded-xl overflow-hidden">
        <table className="w-full text-left text-sm">
          <thead className="bg-slate-950/50 text-slate-400 uppercase font-medium text-xs">
            <tr>
              <th className="px-6 py-4">Name</th>
              <th className="px-6 py-4">Role</th>
              <th className="px-6 py-4">Access Level</th>
              <th className="px-6 py-4">Status</th>
              <th className="px-6 py-4 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800/50">
            {safeStaff.map((staff: StaffMember) => (
              <tr key={staff.id} className="hover:bg-slate-800/30 transition-colors">
                <td className="px-6 py-4">
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-full bg-slate-800 flex items-center justify-center text-xs font-bold text-slate-300">
                        {staff.name.charAt(0)}
                    </div>
                    <div>
                        <div className="font-medium text-white">{staff.name}</div>
                        <div className="text-xs text-slate-500">{staff.email}</div>
                    </div>
                  </div>
                </td>
                <td className="px-6 py-4 text-slate-300">{staff.role}</td>
                <td className="px-6 py-4">
                   <div className={cn("inline-flex items-center gap-1.5 px-2 py-1 rounded text-xs font-medium border",
                       staff.access === 'Admin' ? "bg-purple-500/10 text-purple-400 border-purple-500/20" : "bg-slate-800 text-slate-400 border-slate-700"
                   )}>
                       {staff.access === 'Admin' ? <ShieldAlert size={12} /> : <Shield size={12} />}
                       {staff.access}
                   </div>
                </td>
                <td className="px-6 py-4">
                   <span className="text-emerald-500 text-xs font-bold px-2 py-1 bg-emerald-500/10 rounded border border-emerald-500/20">
                       {staff.status}
                   </span>
                </td>
                <td className="px-6 py-4 text-right">
                    <button className="text-slate-500 hover:text-white"><MoreHorizontal size={16} /></button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Add Staff Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
            <div className="bg-slate-900 border border-slate-800 rounded-2xl w-full max-w-md p-6 shadow-2xl relative">
                <button 
                    onClick={() => setIsModalOpen(false)}
                    className="absolute top-4 right-4 text-slate-500 hover:text-white"
                >
                    <X size={20} />
                </button>
                
                <h3 className="text-lg font-bold text-white mb-6">Add New Staff Member</h3>
                
                <div className="space-y-4">
                    <div className="space-y-1">
                        <label className="text-xs font-medium text-slate-400 uppercase tracking-wider">Full Name</label>
