import { LogOut, ChevronLeft, ChevronRight, type LucideIcon } from "lucide-react";

export interface NavItem {
  href: string;
  label: string;
  icon: LucideIcon;
}

export interface PanelConfig {
  panelName: string;
  basePath: string;
  theme: 'admin' | 'member';
  navItems: NavItem[];
  userProfile: {
    name: string;
    role: string;
    initials?: string;
    avatarUrl?: string;
  };
}

export default function AppSidebar({
  config,
  isOpen,
  toggleSidebar,
}: {
  config: PanelConfig;
  isOpen: boolean;
  toggleSidebar?: () => void;
}) {
  const pathname = usePathname();
  const isMember = config.theme === 'member';

  return (
    <aside
