                {values.map((item, index) => {
                    const step = 0.25; // Fixed step/duration for each item
                    const start = index * 0.22; // Slight overlap
                    const end = start + step;
                    
                    return (
                        <ValueItem 
                            key={item.id} 
                            item={item} 
                            progress={scrollYProgress} 
                            range={[start, end]}
                        />
                    );
                })}
            </div>
        </div>
