const SHEETS_API_URL = process.env.NEXT_PUBLIC_SHEETS_API_URL || '';

export const api = {
    // Generic Fetch
    async fetchData(type: 'Plans' | 'Maintenance' | 'Members' | 'Leads' | 'Staff'): Promise<any[] | null> {
        if (!SHEETS_API_URL) return null;

        try {
            // Append ?type=... to URL
            const url = `${SHEETS_API_URL}?type=${type}`;
            const response = await fetch(url);
            if (!response.ok) throw new Error(`Failed to fetch ${type}`);
            return await response.json();
        } catch (error) {
            console.error(`API Fetch Error (${type}):`, error);
            return null;
        }
    },

    // Generic Save
    async saveData(type: 'Plans' | 'Maintenance' | 'Members' | 'Leads' | 'Staff', data: unknown[]): Promise<boolean> {
        if (!SHEETS_API_URL) return false;

        try {
            const payload = {
                type, // "Plans", "Maintenance", etc.
                data
            };
            
            // Apps Script Web App "Anyone" usually requires no-cors for simple POSTs 
            // but we send text/plain to avoid preflight issues if possible.
            await fetch(SHEETS_API_URL, {
                method: 'POST',
                mode: 'no-cors',
                headers: { 'Content-Type': 'text/plain' },
                body: JSON.stringify(payload)
            });
            
            return true;
        } catch (error) {
            console.error(`API Save Error (${type}):`, error);
            return false;
        }
    }
};

import 'dotenv/config';
import { db } from '../lib/db';
import { plans } from '../lib/db/schema';
import { eq } from 'drizzle-orm';
import fs from 'fs';

async function run() {
  const logs: string[] = [];
  const log = (...args: unknown[]) => {
      console.log(...args);
      logs.push(args.map(a => JSON.stringify(a, null, 2)).join(' '));
  };
  
  log("🔍 STARTING DATABASE DEBUG CHECKS...");
  
  try {
      // 1. Check Connection
      log("1️⃣ Testing connection...");
      const result = await db.select().from(plans);
      log(`✅ Connection success. Found ${result.length} existing plans.`);
      log("Current rows:", result);

      // 2. Attempt Insert
      log("\n2️⃣ Attempting DIRECT INSERT via script...");
      const testName = `Debug Plan ${Date.now()}`;
      const inserted = await db.insert(plans).values({
          name: testName,
          price: 9999,
          features: ['Debug Feature'],
          isActive: true
      }).returning();
      
      log("✅ Insert returned:", inserted);

      // 3. Verify Persistence immediately
      log("\n3️⃣ Verifying persistence (Fetching again)...");
      const resultAfter = await db.select().from(plans);
      const found = resultAfter.find(p => p.name === testName);
      
      if (found) {
          log("🎉 SUCCESS: Plan persisted and retrieved!");
      } else {
          log("❌ FAILURE: Inserted plan NOT found in subsequent select!");
      }

  } catch (error) {
      log("❌ CRITICAL ERROR:", error);
  } finally {
      fs.writeFileSync('debug_result.txt', logs.join('\n'));
      process.exit(0);
  }
}

run();

